    // lc_dptDistrictCd, lc_arvDistrictCd 컴포넌트가 X > 전역변수로 ""값세팅
    if (gubun == "1") {
        // scwin.setDistrictCd("1");
    } else if (gubun == "2") {
        // scwin.setDistrictCd("2");
    } else {
        // scwin.setDistrictCd("1");
    }
};

scwin.setDistrictCd = function(gubun) {
    if (gubun == "1") {
        //복화권역
        const param= [
            {
                method: "getLuxeComboDataNcall",
                param1: "NcallDsCommonEBC",
                param2: "retriveWrkDistrictCdCombo",
                param3: ["CMP"],
                compID: "lc_dptDistrictCd, lc_arvDistrictCd"
            }
        ];
        $c.data.setGauceUtil(param, function() {
            dlt_gauceUtil_lc_dptDistrictCd_lc_arvDistrictCd.setRowJSON(0, {"code":"","name":"전체"}, false);
            lc_dptDistrictCd.setSelectedIndex(0);
            lc_arvDistrictCd.setSelectedIndex(0);
        });

    } else if (gubun == "2") {
        //부산매입권역
        const param= [
            {
                method: "getLuxeComboDataNcall",
                param1: "NcallDsCommonEBC",
                param2: "retriveWrkRgnCdCombo",
                param3: ["PUS"],
                compID: "lc_dptDistrictCd, lc_arvDistrictCd"
            }
        ];
        $c.data.setGauceUtil(param, function() {
            lc_dptDistrictCd.setSelectedIndex(0);
            lc_arvDistrictCd.setSelectedIndex(0);
        });
    }
};


//-------------------------------------------------------------------------
// 셔틀운송작업지시등록 링크
//-------------------------------------------------------------------------
scwin.f_goWrkIndict = async function() {
    if (ds_results.getRowCount() == 0 || ds_results.getRowPosition() < 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["오더"]);
        return;

    } else {
        let rowPos = ds_results.getRowPosition();
        let v_lobranCd = lc_lobranCd.getValue();
        let v_wrkStDt = ds_results.getCellData(rowPos, "wrkStDt");
        let v_wrkEndDt = ds_results.getCellData(rowPos, "wrkEndDt");
        let v_odrNo = ds_results.getCellData(rowPos, "odrNo");

        if ($c.gus.cfIsNull(v_odrNo)) {
            await $c.gus.cfAlertMsg("오더를 선택하십시요");
            return;
        }

        let param = {
            odrNo: v_odrNo,
            lobranCd: v_lobranCd,
            wrkStDt: v_wrkStDt,
            wrkEndDt: v_wrkEndDt
        };
        $c.win.openMenu("셔틀운송작업지시등록(컨테이너)", DsConstants.URL_CONTAINER_SHUTTLE_TRANS_VOLUME, "op_202_02_07b.xml", param);
    }
};


//-------------------------------------------------------------------------
// 신규 프린트
// 오더SHEET는 현재 화면에서 진행하므로 이전 함수 호출
// CNTR LOADING LIST, CNTR DISCHARGING LIST는 팝업화면으로 파라메터 전달
//-------------------------------------------------------------------------
scwin.f_printNew = async function(gubun) {
    let checkCnt = 0;   //체크박스 체크개수
    let batchYn = 0;    //일괄여부
    let v_odrNo = "";
    let tmpStr = "";
    let pURL = "";      //page경로

    if (ds_results.getRowCount() == 0 || ds_results.getRowPosition() < 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["오더"]);
        return;

    } else {
        let tmpOdr = "";
        //일괄발행시 적용할 오더번호 추출
        for (let i = 0; i < ds_results.getRowCount(); i++) {
            if (scwin.f_IsSelected(i)) {
                if (checkCnt == 0) {
                    tmpStr = tmpStr + ds_results.getCellData(i, "odrNo");
                } else {
                    if (tmpOdr != ds_results.getCellData(i, "odrNo")) {
                        tmpStr = tmpStr + "," + ds_results.getCellData(i, "odrNo");
                    }
                }
                tmpOdr = ds_results.getCellData(i, "odrNo");
                checkCnt++;
            }
        }

        if (checkCnt > 1) {
            batchYn = 1;
            v_odrNo = tmpStr;
        } else {
            let rowPos = ds_results.getRowPosition();
            v_odrNo = ds_results.getCellData(rowPos, "odrNo");
        }

        switch(gubun) {
            case 1:
                pURL = "/ui/ds/op/wrkplan/transwrkplan/op_202_02_05r.xml";
                await $c.win.openPopup(pURL, {
                    width: 530,
                    height: 300,
                    modal: true,
                    data: { odrNo: v_odrNo, batchYn: batchYn }
                });
                break;
            case 2:
                pURL = "/ui/ds/op/wrkplan/transwrkplan/op_202_02_04r.xml";
                await $c.win.openPopup(pURL, {
                    width: 530,
                    height: 300,
                    modal: true,
                    data: { odrNo: v_odrNo, batchYn: batchYn }
                });
                break;
            case 3: //오더SHEET
                if (batchYn) {
                    scwin.f_print(4);   //일괄print (viewer띄우지 않고 print)
                } else {
                    scwin.f_print(3);   //개별print (viewer띄어서 print)
                }
                break;
            default:
                break;
        }
    }
};


//-------------------------------------------------------------------------
// 파일 확장자 체크
//-------------------------------------------------------------------------
scwin.f_CheckFileExt = function(ext, path) {
    ext = ext.toUpperCase();
    path = path.toUpperCase();
    let elen = ext.length;
    let flen = path.length;
    return (ext == path.substring((flen - elen), flen));
};


//-------------------------------------------------------------------------
// 파일 업로드
//-------------------------------------------------------------------------
scwin.f_upload = async function() {
    //TODO 업로드 기능 있는지 확인필요함

    ds_excel.removeAll();
    ds_excelTmp.removeAll();

    // UDC_ID.uploadGridViewExcel(gr_tariff, options)

    $c.gus.cfProgressWinClose();

    let chk = await $c.win.confirm("업로드작업이 완료되었습니다. 저장하시겠습니까?");
    if (chk) {
        await $c.sbm.execute(sbm_upload_save);
    }
};


//-------------------------------------------------------------------------
// 프린트
//-------------------------------------------------------------------------
scwin.f_print = async function(gubun) {
    if (ds_results.getRowCount() == 0 || ds_results.getRowPosition() < 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["오더"]);
        return;

    } else {
        let rowPos = ds_results.getRowPosition();
        let v_odrNo = ds_results.getCellData(rowPos, "odrNo");

        switch (gubun) {
            case 1:
                if ($c.gus.cfIsNull(v_odrNo)) {
                    await $c.gus.cfAlertMsg("오더를 선택하십시요");
                    return;
                }
                let pURL1 = "/ui/ds/op/wrkplan/transwrkplan/op_202_02_05r.xml";
                await $c.win.openPopup(pURL1, {
                    width: 530,
                    height: 300,
                    modal: true,
                    data: { odrNo: v_odrNo }
                });
                break;

            case 2:
                if ($c.gus.cfIsNull(v_odrNo)) {
                    await $c.gus.cfAlertMsg("오더를 선택하십시요");
                    return;
                }
                let pURL2 = "/ui/ds/op/wrkplan/transwrkplan/op_202_02_04r.xml";
                await $c.win.openPopup(pURL2, {
                    width: 530,
                    height: 300,
                    modal: true,
                    data: { odrNo: v_odrNo }
                });
                break;

            case 3:
                if ($c.gus.cfIsNull(v_odrNo)) {
                    await $c.gus.cfAlertMsg("오더를 선택하십시요");
                    return;
                }

                let data = {
                    odiName : "op_202_02_03r",
                    reportName: "/ds/op/wrkplan/transwrkplan/op_202_02_03r.ozr",
                    odiParam :{
                        odrNo: v_odrNo
                    },
                    viewerParam : {
                        zoom : 100, // 배율 설정
                    },
                    formParam : {

                    }
                };
                scwin.openPopup(data);

                break;

            case 4:
                let checkCnt4 = 0;
                for (let i = 0; i < ds_results.getRowCount(); i++) {
                    if (scwin.f_IsSelected(i)) checkCnt4++;
                }
                if (checkCnt4 == 0) {
                    await $c.gus.cfAlertMsg("일괄 발행할 오더를 선택하십시요.");
                    return;
                }

                $c.gus.OZStartBatch();
                let printCnt = 0;
                let firstOdrNo = "";
                let chkOdrNo = "";
                for (let i = 0; i < ds_results.getRowCount(); i++) {
                    if (ds_results.getCellData(i, "chk") == "T") {
                        let batchOdrNo = ds_results.getCellData(i, "odrNo");
                        if (printCnt == 0) firstOdrNo = batchOdrNo;
                        if (chkOdrNo == batchOdrNo) continue;
                        if (chkOdrNo !== batchOdrNo) chkOdrNo = batchOdrNo;

                        let data = {
                            odiName : "op_202_02_03r",
                            reportName: "/ds/op/wrkplan/transwrkplan/op_202_02_03r.ozr",
                            odiParam :{
                                odrNo: v_odrNo
                            },
                            viewerParam : {
                                zoom : 100, // 배율 설정
                                mode : "print",
                                useprogressbar : false, // 프로그레스바 쓸지 말지
                                printmode: "silent"
                            },
                            formParam : {

                            }
                        };
                        scwin.openPopup(data);

                        printCnt++;
                    }
                }
                // $c.gus.OZExecuteBatch();
                if (printCnt == 1) await $c.win.alert(firstOdrNo + "의 오더Sheet를 프린터로 전송했습니다.");
                if (printCnt > 1) await $c.win.alert(firstOdrNo + "외에 " + (printCnt - 1) + "건의 오더Sheet를 프린터로 전송했습니다.");
                break;

            default:
                break;
            }
    }
};


scwin.openPopup = async function(data){
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};


//-------------------------------------------------------------------------
// 선택된 행인지 여부를 반환
//-------------------------------------------------------------------------
scwin.f_IsSelected = function(row) {
    if (row < 0) {
        return false;
    }

    if (ds_results.getCellData(row, "chk") == "T") {
        return true;
    } else {
        return false;
    }
};


